// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract AdoptAUkrainianGirl is ReentrancyGuard {
    using SafeMath for uint256;

    string public constant name = "Adopt A Ukrainian Girl";
    string public constant symbol = "AAUG";
    uint8 public constant decimals = 18;
    uint256 public constant totalSupply = 1_000_000 * (10 ** uint256(decimals));
    address public immutable owner;
    bool public tradingEnabled = false;
    uint256 public liquidityFee = 2;
    uint256 public marketingFee = 2;
    uint256 public totalLiquidityFees;
    uint256 public totalMarketingFees;
    address public uniswapV2Pair;
    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event SwapTokensForEth(uint256 tokenAmount, uint256 liquidityFeeAmount, uint256 marketingFeeAmount);

    constructor() {
        owner = msg.sender;
        _balances[owner] = totalSupply;
        emit Transfer(address(0), owner, totalSupply);
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier tradingAllowed() {
        require(tradingEnabled || msg.sender == owner, "Trading not enabled");
        _;
    }

    function setTrading(bool _enabled) external onlyOwner {
        tradingEnabled = _enabled;
    }

    function transfer(address recipient, uint256 amount) external nonReentrant tradingAllowed returns (bool) {
        require(_balances[msg.sender] >= amount, "Insufficient balance");
        _balances[msg.sender] -= amount;
        _balances[recipient] += amount;
        emit Transfer(msg.sender, recipient, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        _allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address sender, address recipient, uint256 amount) external nonReentrant tradingAllowed returns (bool) {
        require(_balances[sender] >= amount, "Insufficient balance");
        require(_allowances[sender][msg.sender] >= amount, "Allowance exceeded");
        _balances[sender] -= amount;
        _balances[recipient] += amount;
        _allowances[sender][msg.sender] -= amount;
        emit Transfer(sender, recipient, amount);
        return true;
    }

    function swapTokensForEth(uint256 tokenAmount) external onlyOwner {
        require(uniswapV2Pair != address(0), "Uniswap V2 pair not set");
        require(tokenAmount <= _balances[msg.sender], "Insufficient balance");

        // Effects
        uint256 liquidityFeeAmount = tokenAmount.mul(liquidityFee).div(100);
        uint256 marketingFeeAmount = tokenAmount.mul(marketingFee).div(100);
        uint256 tokensToSwap = tokenAmount.sub(liquidityFeeAmount).sub(marketingFeeAmount);

        _balances[msg.sender] -= tokenAmount;
        _balances[address(this)] += tokensToSwap;

        totalLiquidityFees += liquidityFeeAmount;
        totalMarketingFees += marketingFeeAmount;

        // Interactions
        // Simulate swap logic (this would involve interacting with UniswapV2Router)
        // For simplicity, we'll just update the balances and fees here
        emit SwapTokensForEth(tokenAmount, liquidityFeeAmount, marketingFeeAmount);
    }

    function setUniswapV2Pair(address _uniswapV2Pair) external onlyOwner {
        uniswapV2Pair = _uniswapV2Pair;
    }

    receive() external payable {}

    // Helper function to approve token spending for UniswapV2Router
    function _approve(address owner, address spender, uint256 amount) internal {
        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
}
